const express = require('express');
const request = require('request');
const app = express();
const port = process.env.PORT || 8080;

app.use(express.json());

app.post('/webhookproxy', (req, res) => {
    const targetUrl = req.body.targetUrl;

    if (!targetUrl) {
        return res.status(400).send('TargetUrl is required');
    }

    request(targetUrl, function (error, response, body) {
        if (error) {
            console.log('Error fetching from targetUrl: ', error);
            return res.status(500).send('Failed to fetch from targetUrl');
        }

        res.send(body);
    });
});

app.listen(port, () => {
    console.log('Webhook proxy running on port ' + port);
});